pub fn cloudshell_users_environments_generate_access_token_builder(
    client: &SimpleHttpClient,
    environment: &str,
    expireTime: Option<&str>,
    ttl: Option<&str>,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!(
        "https://cloudshell.googleapis.com/v1/users/{}/environments/{}:generateAccessToken",
        environment,
    );

    // Build request
    let mut query_parts = Vec::new();
    if let Some(val) = expireTime {
        query_parts.push(format!("expireTime={}", val));
    }
    if let Some(val) = ttl {
        query_parts.push(format!("ttl={}", val));
    }

    let url_with_query = if query_parts.is_empty() {
        url
    } else {
        format!("{}?{}", url, query_parts.join("&"))
    };

    let builder = client
        .get(&url_with_query)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?;

    Ok(builder)
}

